  1	import type { SessionStorage } from "../session/storage.ts";
  2	
  3	// 内部结构:一条注册记录
  4	interface Entry<K extends HookKind> {
  5	    matcher: Matcher;
  6	    hook: Hook<HookContexts[K]>;
  7	}
  8	
  9	
 10	// ============================================================
 11	// 1) 每种 hook 的 ctx 结构
 12	// ============================================================
 13	export interface HookContexts {
 14	    sessionStart: {
 15	        storage: SessionStorage;
 16	        systemPromptExtras: string[];   // hook 可以往这里 push 内容,拼进 system prompt
 17	    };
 18	    userPromptSubmit: {
 19	        input: string;                  // 用户原始输入,hook 可以改写
 20	        storage: SessionStorage;
 21	    };
 22	    preToolUse: {
 23	        toolName: string;
 24	        args: Record<string, unknown>;  // hook 可以改参数
 25	        storage: SessionStorage;
 26	    };
 27	    postToolUse: {
 28	        toolName: string;
 29	        args: Record<string, unknown>;
 30	        result: string;                 // hook 可以改结果
 31	        storage: SessionStorage;
 32	    };
 33	}
 34	
 35	export type HookKind = keyof HookContexts;
 36	
 37	// ============================================================
 38	// 2) Hook 返回值:三种情况都要能表达
 39	// ============================================================
 40	export interface HookResult<C> {
 41	    block?: boolean;    // 阻断后续 hook,主流程也知道被拦
 42	    reason?: string;    // 阻断原因(打日志用)
 43	    ctx?: C;            // 替换 ctx,后续 hook 和主流程都用新的
 44	}
 45	
 46	// hook 函数本体:同步或异步都行
 47	export type Hook<C> =
 48	    | ((ctx: C) => void | HookResult<C>)
 49	    | ((ctx: C) => Promise<void | HookResult<C>>);
 50	
 51	// ============================================================
 52	// 3) matcher:注册时带的,决定 hook 是否被激活
 53	// ============================================================
 54	export type Matcher = string | string[] | "*";
 55	
 56	// ============================================================
 57	// 4) HookRegistry.run() 的返回值
 58	// ============================================================
 59	export interface HookRunResult<C> {
 60	    ctx: C;             // 最终 ctx(可能被 hook 改过)
 61	    blocked: boolean;   // 主流程要看这个决定是否继续
 62	    reason?: string;    // 阻断原因
 63	}
 64	
 65	export class HookRegistry {
 66	    // 每种 kind 一个数组
 67	    private hooks: { [K in HookKind]: Entry<K>[] } = {
 68	        sessionStart: [],
 69	        userPromptSubmit: [],
 70	        preToolUse: [],
 71	        postToolUse: [],
 72	    };
 73	
 74	    // ============================================================
 75	    // 注册
 76	    // ============================================================
 77	    register<K extends HookKind>(
 78	        kind: K,
 79	        matcher: Matcher,
 80	        hook: Hook<HookContexts[K]>,
 81	    ): void {
 82	        // 需要 as 断言:TS 无法证明这个数组元素的 K 就是当前 K
 83	        // 但我们通过泛型约束保证了运行时正确
 84	        (this.hooks[kind] as Entry<K>[]).push({ matcher, hook });
 85	    }
 86	
 87	    // ============================================================
 88	    // 触发
 89	    // ============================================================
 90	    async run<K extends HookKind>(
 91	        kind: K,
 92	        ctx: HookContexts[K],
 93	        toolNameForMatch?: string,
 94	    ): Promise<HookRunResult<HookContexts[K]>> {
 95	        const entries = this.hooks[kind] as Entry<K>[];
 96	        let currentCtx = ctx;
 97	
 98	        for (const entry of entries) {
 99	            // ---- 1. 判断 matcher 是否命中 ----
100	            if (!this.matches(entry.matcher, toolNameForMatch)) continue;
101	
102	            // ---- 2. 执行 hook,always await(同步返回也可以 await)----
103	            let result: void | HookResult<HookContexts[K]>;
104	            try {
105	                result = await entry.hook(currentCtx);
106	            } catch (err) {
107	                // hook 抛异常:打日志,跳过这个 hook,不影响其他
108	                console.error(
109	                    `[hook] ${kind} hook threw, skipped:`,
110	                    (err as Error).message,
111	                );
112	                continue;
113	            }
114	
115	            // ---- 3. 空返回:观察者,继续下一个 ----
116	            if (!result) continue;
117	
118	            // ---- 4. 有返回:先更新 ctx(即使被 block 也更新,方便日志)----
119	            if (result.ctx !== undefined) {
120	                currentCtx = result.ctx;
121	            }
122	
123	            // ---- 5. 阻断:立即返回,不跑后续 hook ----
124	            if (result.block) {
125	                return { ctx: currentCtx, blocked: true, reason: result.reason };
126	            }
127	        }
128	
129	        return { ctx: currentCtx, blocked: false };
130	    }
131	
132	    // ============================================================
133	    // matcher 匹配逻辑
134	    // ============================================================
135	    private matches(matcher: Matcher, name: string | undefined): boolean {
136	        // 通配
137	        if (matcher === "*") return true;
138	        // SessionStart / UserPromptSubmit 这类没有 toolName 的 hook,
139	        // 只有 "*" matcher 才生效;传具体名字给它们没意义
140	        if (name === undefined) return false;
141	        if (typeof matcher === "string") return matcher === name;
142	        return matcher.includes(name);
143	    }
144	}
